var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"하아, 하아……. 가, 간신히 손에 넣었어.","JPN":"はあ、はあ……や、やっと手に入れた。","ENG":"*Huff, huff...* I-I finally got it...!","TWN":"呼呼呼…終於…弄到手。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"이 약만 있다면…… 오늘도 편안히…….","JPN":"この薬さえあれば……今日もぐっすり……","ENG":"With \\"this\\"... I can finally sleep...","TWN":"只要有這個藥……我今天就可以安心地……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"어, 어라? 내가 문을 안 잠갔던가……?","JPN":"あ、あれ？　俺、鍵をかけなかったっけ……？","ENG":"H-huh? Didn't I lock the door on my way out...?","TWN":"奇怪？我沒把門關好嗎……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_QM","text":{"KOREA":"마침 한 권을 다 읽은 참이었습니다, 늦으셨군요.","JPN":"ちょうど一冊読み終えたところです、遅かったのですね。","ENG":"I have just finished reading an entire book. You are late...","TWN":"遲到囉，我都讀完一本書了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_QM","text":{"KOREA":"……클락 헤밍턴 형제.\xA0","JPN":"……クラーク・ハミントン兄弟。\xA0","ENG":"Brother Clark Hammington...\xA0","TWN":"……克拉克·海明頓弟兄。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"누, 누구야 당신!? 어떻게 여길……!?","JPN":"だ、誰だ、あんた！？　どうやってここに……！？","ENG":"W-who're you?! H-how did you...?!","TWN":"你…你是誰！？怎麼會來這裡……？！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제 이름은 비블리데 루체. 당신을 열람하기 위해 찾아왔습니다.","JPN":"私の名はビブリデ・ルーチェ。あなたを閲覧するためにきました。","ENG":"My name is Biblide Luce. I have come to browse you.","TWN":"我叫布莉黛·露契，是來閱覽你的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐만…… 그 복장…….","JPN":"ま、待てよ……その服装は……","ENG":"W-wait! That uniform...","TWN":"先…等一下……看你的服裝……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"서, 설마 당신……! 성황청에서!?","JPN":"ま、まさかあんた……！　聖皇庁から！？","ENG":"Y-you're from...! The Holy Curia?!","TWN":"你…你是……！聖皇廳派來的！？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……철퇴 용병단.","JPN":"……鉄槌傭兵団。","ENG":"Mace Mercenary...","TWN":"……鐵鎚傭兵團。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청의 의뢰라면 어떤 일이든 서슴지 않고 수행하는, 신앙심 투철한 용병단이죠.","JPN":"聖皇庁の依頼ならどんなことでもためらわずに遂行する、信仰深い傭兵団です。","ENG":"The devoted Mace Mercenary will gladly comply to any request from the Holy Curia.","TWN":"舉凡是聖皇廳的委託，絕對不遲疑，以堅定的信念完成使命的傭兵團。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러나 그들은 얼마 전 소리소문 없이 행방이 묘연해졌습니다.","JPN":"ですが、彼らは少し前にひっそりと姿を消しました。","ENG":"However, they disappeared without a trace a couple of days ago.","TWN":"但是在不久前，他們卻突然下落不明。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"덕분에 용병들 사이에서는 한동안 이런 괴소문이 돌았죠.","JPN":"おかげで傭兵の間では、しばらくこんな噂がささやかれたのです。","ENG":"As a result, strange rumors have been circulating among the mercenaries.","TWN":"然而在傭兵之間一直有這樣的傳言，"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"철퇴 용병단은 성무를 수행하던 중 실종됐고, 성황청은 그 사실을 은폐하고 있다고.","JPN":"鉄槌傭兵団は聖務を遂行する途中に失踪し、聖皇庁はその事実を隠ぺいしていると。","ENG":"Mace Mercenary vanished during a sacred mission, and the Holy Curia is trying to cover up this fact.","TWN":"說鐵鎚傭兵團在執行聖務時失蹤，聖皇廳則隱瞞事實。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"……어, 어이.","JPN":"……お、おい。","ENG":"H-hey...","TWN":"那是……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 소문은 어디까지나 소문일 뿐, 실제로는 어땠는지 아무도 알 수 없죠.","JPN":"しかし噂はあくまでも噂。実際どうだったかは誰も知りません。","ENG":"But a rumor is just that. A rumor. No one knows what really happened.","TWN":"不過傳言終究是傳言，沒人知道真相到底為何。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 괴소문의 당사자들은 이미 세상에 존재하지 않으니까요.","JPN":"噂の当事者たちはすでにこの世に存在しないのですから。","ENG":"Mostly because everyone involved no longer exists in this world.","TWN":"因為傳言中的當事者，早已不存在於這個世界上。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐만……! 나는 아무것도 몰라!","JPN":"ま、待て……！　俺は何も知らないんだ！","ENG":"W-wait...! I don't know anything!","TWN":"等等……！我什麼都不知道！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 만약…… 그 철퇴 용병단의 생존자가 존재한다면?","JPN":"でも、もし……鉄槌傭兵団の生存者が存在するとしたら？","ENG":"If only... There was a survivor from Mace Mercenary...?","TWN":"但會不會……其實鐵鎚傭兵團中還有倖存者？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"정말이야!! 나는 그때 신참이라서 운 좋게 작전에 투입되지 않았어!!","JPN":"本当だ！！　俺はあの時新米だったから、運よく作戦には投入されなかったんだ！！","ENG":"I swear to you!! I was a rookie at the time, so I was fortunate not to be involved in the operation!!","TWN":"是真的！我當時還只是個菜鳥，所以才幸運不用參與作戰！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"믿어 줘! 나는 <color=#ffd34c>성무 SI3E</color>와 관계없다고!!","JPN":"信じてくれ！　俺は<color=#ffd34c>聖務SI3E</color>とは関係がないんだよ！！","ENG":"You got to believe me! I have nothing to do with <color=#ffd34c>Sacred Mission SI3E</color>!!","TWN":"你相信我！我和<color=#ffd34c>聖務SI3E</color>沒有任何關係！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"관계없다? 다시 말해, 당신은 아무것도 목격하지 못했다는 말씀이신가요?","JPN":"関係がない？　と言いますと、あなたは何も目撃していないということですか？","ENG":"\\"Nothing to do with it\\", eh? So you are telling me you witnessed nothing?","TWN":"沒有任何關係？我再問你一次，你真的什麼都沒看到嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그, 그래! 나는 아무것도 못 봤어!!","JPN":"そ、そうだ！　俺は何も見ていない！！","ENG":"Y-yes! I saw nothing!!","TWN":"真…真的！我什麼都沒看到！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그러니까 시간낭비 하지 말고…….","JPN":"だから時間の無駄はやめて……","ENG":"Then stop wasting your time and─","TWN":"你就別在我身上浪費時間……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼 그 손에 들고 있는 종이 봉투에는 뭐가 들어 있죠?","JPN":"それでは、その手に持っている紙袋には何が入っているのですか？","ENG":"What could possibly be in that paper bag of yours, hmm?","TWN":"那你手上的紙袋裡裝的是什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"이, 이건…….","JPN":"こ、これは……","ENG":"Th-this is...","TWN":"這…這是……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"말씀하고 싶지 않으시다면, 제가 대신 말씀드리도록 하죠.","JPN":"話したくないのなら、私が代わりに話してさしあげましょう。","ENG":"If you are not willing to tell me, I will say it for you.","TWN":"你不想說的話，那我來幫你說吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 안에는 최근 유행하고 있는 신종 마약이 들어 있을 겁니다.","JPN":"その中には最近流行している新種の麻薬が入ってるはずです。","ENG":"The contents of that bag should be the new drug circulating in the area.","TWN":"裡面裝的應該是最近流行的新型態毒品。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"불행한 기억을 잊고, 행복한 환각을 보여 준다고 해서 성냥이라고 부른다더군요.","JPN":"不幸な記憶を忘れ、幸せな幻覚を見せてくれることからマッチと呼ばれているらしいですね。","ENG":"I believe they are called \\"matches\\", making you forget bad memories and giving you hallucinations of good ones.","TWN":"可以忘掉不愉快的回憶，產生幸福的幻覺，因此取名為火柴。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"즉, 당신에게는 약의 힘을 빌려서라도 잊고 싶은 기억이 있다는 뜻이겠죠.","JPN":"つまり、あなたには薬の力を借りてでも忘れたい記憶があるということでしょう。","ENG":"In other words, there is something you wish to forget with the help of drugs.","TWN":"也就是說，你有想藉著藥物的力量來忘掉的回憶吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……그렇지 않나요, 헤밍턴 형제?","JPN":"……そうではありませんか？　ハミントン兄弟。","ENG":"Isn’t that right, Brother Hammington?","TWN":"……我有說錯嗎？海明頓弟兄？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"요 며칠, 당신을 읽어 봤습니다.","JPN":"この数日、あなたを読んでみました。","ENG":"I've been reading up on you for these past few days.","TWN":"我已經，閱讀你好幾天。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"깨어 있는 동안에는 도박과 술에, 잠들 때는 약물에 의존하고 있죠.","JPN":"目覚めている間は賭博と酒に、眠る時には薬物に頼っていますね。","ENG":"You gamble and drink during the day, and use that drug to sleep at night.","TWN":"你醒著的時候不是在賭博就是喝酒，晚上則需要靠藥物入眠。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"거울을 보세요. 성무 SI3E는 당신의 삶을 완전히 망가트렸습니다.","JPN":"鏡を見てください。聖務SI3Eはあなたの人生を完全に破壊してしまいました。","ENG":"Take one look at yourself in the mirror. Your whole life is ruined because of Sacred Mission SI3E.","TWN":"你照照鏡子，聖務SI3E完全毀了你的人生。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"구태여, 말하지 않아도 당신의 결말을 알고 있겠죠.","JPN":"あえて言わずとも、あなたは結末がわかっているでしょう。","ENG":"And you must also know how this will end.","TWN":"不用我說，你也知道你的下場會如何吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"도망치고 외면하기만 해서는 아무것도 바꿀 수 없다는 것을…….","JPN":"逃げて目を背けるだけでは何も変えられないということを……","ENG":"Nothing will change if you keep running away from your problems...","TWN":"逃避是無法改變任何事情的……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"하, 하지만…… 나는……!!","JPN":"け、けど……俺は……！！","ENG":"B-but... I...!!","TWN":"可…可是……我……！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"나 때문에…… 넬슨 수녀님이…….","JPN":"俺のせいで……シスターネルソンが……","ENG":"Because of me... Sister Nelson...","TWN":"尼爾森修女……因為我的關係……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그래! 결국 나한테 책임을 물으러 온 거지?! 수녀님의 복수를 하려고!","JPN":"そうだ！　結局俺に責任を問いに来たんだろ！？　シスターの復讐のために！","ENG":"So! You're here to take me in, right?! To avenge Sister Nelson!","TWN":"對！你是來向我追究責任的吧？！你要替修女報仇是嗎！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"맞아, 그런 게 아니라면 대체 왜……!?","JPN":"そうなんだ、そうでなけりゃいったいなんで……！？","ENG":"Yes... If it's not that, then why...?!","TWN":"一定是這樣，否則你為什麼……！？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해 드리죠. \xA0","JPN":"喜んで訂正いたします。\xA0 ","ENG":"I would be more than happy to rephrase.\xA0","TWN":"我要更正一下。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저는 성황청을 대변해서 여기 온 것도, 당신을 지탄하러 온 것도 아닙니다.","JPN":"私がここに来た理由は、聖皇庁の立場を伝えるためでも、あなたを責めるためでもありません。","ENG":"I am not here on behalf of the Holy Curia, nor am I here to criticize you.","TWN":"我不是代替聖皇廳來找你，也不是來指責你的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"다만, 사람을 찾고 있을 뿐입니다.","JPN":"ただ、人を探しているだけです。","ENG":"I am, however, looking for someone.","TWN":"我只是，在找人而已。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"사람을…… 찾고 있다고?","JPN":"人を……探してるだと？","ENG":"Looking... for someone?","TWN":"你在……找人？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"네. 성무 SI3E를 읽어나가다 보면, 그 자에게 닿을 수 있겠죠.","JPN":"はい。聖務SI3Eを読んでいけば、その人にたどり着くことができるでしょう。","ENG":"Yes, if I read up more on Sacred Mission SI3E, I will be able to locate him.","TWN":"對，聖務SI3E只要繼續讀下去，應該就可以找到他吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"협력해 주신다면 제가 당신의 고해성사를 도와드리도록 하겠습니다.","JPN":"協力していただけるのでしたら、告解をお手伝いいたします。","ENG":"If you cooperate, I will assist you with your confession.","TWN":"你願意幫我的話，那我可以幫你告解。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"고해성사를……? 어떻게……?","JPN":"告解を……？　どうやって……？","ENG":"My confession...? But how...?","TWN":"告解……？要怎麼做……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그건 \xA0지금부터 당신이 어떤 답변을 하느냐에 따라 다를 겁니다.","JPN":"それは今からあなたがどのように答えるかにかかっています。","ENG":"That will depend on how you answer my questions.","TWN":"做法會根據你的回答而有所不同。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"지금처럼 과거에 얽매인 삶을 살 것인지. 혹은 앞으로 한 걸음 나아갈 것인지.","JPN":"今のように過去に囚われた人生を生きるか。それとも前へ一歩前進するか。","ENG":"Are you going to keep living in the past, or are you going to take a step forward?","TWN":"你是要繼續像這樣困在過去，還是往前邁一步呢？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"선택은 오롯이 당신의 몫입니다, 클락 헤밍턴 형제.","JPN":"選択はあなた次第です、クラーク・ハミントン兄弟。","ENG":"The choice is up to you, Brother Clark Hammington.","TWN":"克拉克·海明頓弟兄，決定權在你手上。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그 숲은……","JPN":"あの森は……","ENG":"That forest...","TWN":"那個森林……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"그 숲은 우리가 예상했던 것보다 훨씬 깊고 울창했어.","JPN":"あの森は俺たちの予想よりはるかに深くてうっそうとしていたんだ。","ENG":"The forest was much deeper and denser than we had anticipated.","TWN":"那個森林比我們預期的還要茂盛，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MROLL_NPC_NULL_NULL","text":{"KOREA":"거기서 우리는…….","JPN":"そこで俺たちは……","ENG":"There, we...","TWN":"我們在那裡……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};